const e={configEditor:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Lisez la configuration active de votre imprimante directement depuis Moonraker — chaque fichier, analysé en sections et en paramètres, avec les problèmes de structure signalés. En lecture seule pour l'instant ; l'édition guidée arrive prochainement."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Aide"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"À propos de l'éditeur de configuration"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Fermer"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Comment utiliser"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Choisissez un fichier de configuration dans la liste déroulante — printer.cfg est sélectionné par défaut."}},{t:0,b:{t:2,i:[{t:3}],s:"Parcourez ses sections ; cliquez sur l'une d'elles pour développer ses paramètres."}},{t:0,b:{t:2,i:[{t:3}],s:"Consultez la bannière de validation pour les problèmes de structure, comme une section en double."}},{t:0,b:{t:2,i:[{t:3}],s:"Passez en mode Brut pour lire le texte exact du fichier."}}],topics:{sections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Sections et paramètres"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Une configuration Klipper est une liste de blocs [section], chacun contenant des paramètres au format key: value. Ce panneau analyse chaque section — y compris celles dont le nom ressemble à [tmc2209 stepper_x] — et liste ses paramètres avec leur valeur et tout commentaire en ligne. Les valeurs multilignes (comme le gcode: d'une macro) sont conservées intactes."}}},includes:{title:{t:0,b:{t:2,i:[{t:3}],s:"Fichiers inclus"}},body:{t:0,b:{t:2,i:[{t:3}],s:"printer.cfg fait souvent appel à d'autres fichiers avec [include other.cfg] (ou un motif comme [include configs/*.cfg]). Chaque inclusion apparaît comme sa propre entrée ; choisissez le fichier inclus dans la liste déroulante pour examiner ce qu'il définit."}}},validation:{title:{t:0,b:{t:2,i:[{t:3}],s:"Validation"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Après l'analyse, la configuration est vérifiée pour détecter les problèmes de structure qui sont incorrects quel que soit le type de section — un en-tête de section en double, un nom de section vide, ou un paramètre situé en dehors de toute section. Ces éléments apparaissent dans la bannière de validation ; ils ne modifient pas votre fichier."}}},saveConfig:{title:{t:0,b:{t:2,i:[{t:3}],s:"Le bloc SAVE_CONFIG"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Klipper ajoute un bloc généré automatiquement à la fin de printer.cfg (après le marqueur #*#) lorsque vous exécutez SAVE_CONFIG — des résultats de calibration comme les valeurs PID et les offsets Z. Il est affiché mais signalé comme enregistré automatiquement, et il est exclu du nombre de sections modifiables car vous ne devez pas le modifier à la main."}}},readonly:{title:{t:0,b:{t:2,i:[{t:3}],s:"Lecture seule (pour l'instant)"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Cette première version se contente de lire et d'afficher la configuration — rien n'est écrit sur l'imprimante. L'édition guidée avec confirmation (incluant une sauvegarde automatique avant tout enregistrement et un redémarrage ensuite) arrivera dans une prochaine mise à jour."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossaire"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{section:{term:{t:0,b:{t:2,i:[{t:3}],s:"Section"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un bloc [header] regroupant des réglages liés, par ex. [stepper_x] ou [extruder]."}}},parameter:{term:{t:0,b:{t:2,i:[{t:3}],s:"Paramètre"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Une ligne key: value (ou key = value) à l'intérieur d'une section, éventuellement suivie d'un commentaire # en fin de ligne."}}},include:{term:{t:0,b:{t:2,i:[{t:3}],s:"[include]"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Une directive qui intègre un autre fichier de configuration dans printer.cfg, afin de répartir les réglages sur plusieurs fichiers."}}},saveConfig:{term:{t:0,b:{t:2,i:[{t:3}],s:"SAVE_CONFIG"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Le bloc généré automatiquement (après #*#) où Klipper stocke les résultats de calibration — ne le modifiez pas à la main."}}}}},file:{label:{t:0,b:{t:2,i:[{t:3}],s:"Fichier de configuration"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Sélectionnez un fichier…"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualiser"}},loadingList:{t:0,b:{t:2,i:[{t:3}],s:"Chargement des fichiers…"}},emptyList:{t:0,b:{t:2,i:[{t:3}],s:"Aucun fichier de configuration trouvé sur l'imprimante."}}},summary:{sections:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" sections"}]}},params:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" paramètres"}]}},size:{t:0,b:{t:2,i:[{t:4,k:"kb"},{t:3,v:" KB"}]}}},validation:{title:{t:0,b:{t:2,i:[{t:3}],s:"Validation"}},clean:{t:0,b:{t:2,i:[{t:3}],s:"Aucun problème de structure détecté."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Erreur"}},warning:{t:0,b:{t:2,i:[{t:3}],s:"Avertissement"}}},view:{structured:{t:0,b:{t:2,i:[{t:3}],s:"Structuré"}},raw:{t:0,b:{t:2,i:[{t:3}],s:"Brut"}},expandAll:{t:0,b:{t:2,i:[{t:3}],s:"Tout développer"}},collapseAll:{t:0,b:{t:2,i:[{t:3}],s:"Tout réduire"}}},section:{saveBadge:{t:0,b:{t:2,i:[{t:3}],s:"enregistré auto."}},noParams:{t:0,b:{t:2,i:[{t:3}],s:"(aucun paramètre)"}},paramsCount:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" paramètres"}]}},paramHead:{t:0,b:{t:2,i:[{t:3}],s:"Paramètre"}},valueHead:{t:0,b:{t:2,i:[{t:3}],s:"Valeur"}}},edit:{hint:{t:0,b:{t:2,i:[{t:3}],s:"Modifiez le texte brut ci-dessous, puis enregistrez. Une sauvegarde horodatée est créée avant toute écriture."}}},save:{button:{t:0,b:{t:2,i:[{t:3}],s:"Enregistrer"}},saving:{t:0,b:{t:2,i:[{t:3}],s:"Enregistrement…"}},unsaved:{t:0,b:{t:2,i:[{t:3}],s:"Modifications non enregistrées"}},revert:{t:0,b:{t:2,i:[{t:3}],s:"Annuler les modifications"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"Enregistrer sur l'imprimante ?"}},confirmBody:{t:0,b:{t:2,i:[{t:3,v:"Cette opération écrase "},{t:4,k:"file"},{t:3,v:" sur l'imprimante. Une sauvegarde horodatée est enregistrée au préalable, et un redémarrage du firmware est nécessaire pour appliquer la modification."}]}},ack:{t:0,b:{t:2,i:[{t:3}],s:"Je comprends que cela écrit sur l'imprimante"}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Enregistrer"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Annuler"}},done:{t:0,b:{t:2,i:[{t:3,v:"Enregistré. Sauvegarde : "},{t:4,k:"backup"}]}},busy:{t:0,b:{t:2,i:[{t:3}],s:"Refusé : l'imprimante est occupée (impression ou en pause). Réessayez lorsqu'elle est inactive."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Échec de l'enregistrement."}}},restart:{prompt:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrer le firmware pour appliquer votre modification ?"}},button:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrer le firmware"}},restarting:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrage…"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrer le firmware ?"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"FIRMWARE_RESTART recharge la configuration et interrompt brièvement l'imprimante. Ne le faites que lorsqu'elle est inactive."}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrer maintenant"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Annuler"}},done:{t:0,b:{t:2,i:[{t:3}],s:"Redémarrage du firmware demandé."}},busy:{t:0,b:{t:2,i:[{t:3}],s:"Refusé : l'imprimante est occupée. Redémarrez lorsqu'elle est inactive."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Échec du redémarrage."}}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Lecture de la configuration…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"Impossible de lire la configuration depuis l'imprimante."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Réessayer"}}},catalog:{title:{t:0,b:{t:2,i:[{t:3}],s:"Ajouter un bloc de config depuis le catalogue"}},hint:{t:0,b:{t:2,i:[{t:3}],s:"Choisissez une pièce — son bloc Klipper exact (run_current, sense_resistor, noms de broches réels) est ajouté au fichier pour relecture et enregistrement."}},drivers:{t:0,b:{t:2,i:[{t:3}],s:"Drivers"}},motors:{t:0,b:{t:2,i:[{t:3}],s:"Moteurs"}},boards:{t:0,b:{t:2,i:[{t:3}],s:"Cartes"}},pickPlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"Rechercher dans le catalogue…"}},inserted:{t:0,b:{t:2,i:[{t:3,v:"Bloc de "},{t:4,k:"name"},{t:3,v:" inséré — relisez-le en Brut et enregistrez."}]}},noSnippet:{t:0,b:{t:2,i:[{t:3,v:"Aucun bloc de config pour "},{t:4,k:"name"},{t:3,v:"."}]}}},drift:{title:{t:0,b:{t:2,i:[{t:3}],s:"Ce que Klipper exécute"}},pending:{t:0,b:{t:2,i:[{t:3}],s:"Klipper a des changements non enregistrés (un SAVE_CONFIG est en attente) — enregistrer ce fichier maintenant les écraserait. Lancez d'abord SAVE_CONFIG dans la console."}},warningsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Avertissements de config Klipper"}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" valeur(s) sur le disque diffèrent de l'exécuté (modifié sans FIRMWARE_RESTART) :"}]}},adopt:{t:0,b:{t:2,i:[{t:3}],s:"adopter live"}}}}};export{e as default};
